\displaystyle{\begin{aligned}
   {\frac{4}{\frac{1}{y}-\frac{2}{y-1}}} 
      \amp = {\frac{4}{\frac{1}{y}-\frac{2}{y-1}}} \cdot \frac{{y\mathopen{}\left(y-1\right)}}{{y\mathopen{}\left(y-1\right)}} \\
      \amp = {\frac{4y\mathopen{}\left(y-1\right)}{\frac{1}{y}y\mathopen{}\left(y-1\right)-\frac{2}{y-1}y\mathopen{}\left(y-1\right)}} \\
      \amp = {\frac{4y\mathopen{}\left(y-1\right)}{y-1-2y}}, y\ne 0 \text{ and } y\ne 1 \\
      \amp = {\frac{4y\mathopen{}\left(y-1\right)}{y-1-2y}}, y\ne 0 \text{ and } y\ne 1 \\

      \amp = {\frac{4y\mathopen{}\left(y-1\right)}{-y-1}, y\ne 0\hbox{ and }y\ne 1}
\end{aligned}
